const tenant = $('Loop Over Tenants').first().json;
const activity = $('Load Daily Activity').first().json;

const customers = activity.customers || [];
const orders = activity.orders || [];
const chats = activity.chats || [];
const creditUsage = activity.credit_usage || [];
const customerCount = parseInt(activity.customer_count) || 0;
const orderCount = parseInt(activity.order_count) || 0;
const pendingPaymentCount = parseInt(activity.pending_payment_count) || 0;
const dailyRevenue = Number(activity.daily_revenue || 0);
const appointmentCount = parseInt(activity.appointment_count) || 0;
const productOrderCount = parseInt(activity.product_order_count) || 0;

const businessMode = tenant.business_mode || 'product_only';
const isService = businessMode === 'service_only';
const isHybrid = businessMode === 'hybrid_product_led' || businessMode === 'hybrid_service_led';
const orderLabel = isService ? 'booking' : 'order';
const ordersLabel = isService ? 'bookings' : 'orders';

let customerList = 'None';
if (customers.length > 0) {
  customerList = customers.map(c => c.display_name || c.username || 'Unknown').join(', ');
}

let orderSummary = 'No new ' + ordersLabel;
if (orders.length > 0) {
  orderSummary = orders.map(o => {
    const type = o.delivery_type === 'appointment' ? ' 📅' : '';
    const payNote = o.payment_status === 'proof_submitted' ? ' ⏳ proof sent' :
                    o.payment_status === 'unpaid' ? ' 💳 payment pending' : '';
    return o.order_number + type + ' — ₦' + Number(o.total_amount || 0).toLocaleString() + ' (' + o.status + ')' + payNote;
  }).join('\n');
}

let chatSnippets = 'No messages';
if (chats && chats.length > 0) {
  const humanMessages = chats.filter(c => c.msg_type === 'human');
  if (humanMessages.length > 0) {
    chatSnippets = humanMessages.slice(0, 10).map(c => '- ' + (c.content || '').substring(0, 100)).join('\n');
  }
}

let creditSummary = 'No AI activity charged yesterday';
if (creditUsage.length > 0) {
  const totalSpent = creditUsage.reduce((sum, c) => sum + Number(c.naira_spent || 0), 0);
  const labelMap = {
    input_text: 'text messages', input_audio: 'voice notes',
    input_image: 'images received', input_file: 'files received',
    output_voice: 'voice replies', output_image: 'images generated', output_video: 'videos generated'
  };
  const breakdown = creditUsage.map(c => '₦' + Number(c.naira_spent).toLocaleString() + ' on ' + (labelMap[c.action_type] || c.action_type)).join(', ');
  creditSummary = '₦' + totalSpent.toLocaleString() + ' total (' + breakdown + ')';
}

let splitNote = '';
if (isHybrid && (appointmentCount > 0 || productOrderCount > 0)) {
  splitNote = appointmentCount + ' appointment(s), ' + productOrderCount + ' product order(s)\n';
}

const llmPrompt =
  'You are ' + tenant.agent_name + ', the AI business agent for ' + tenant.business_name + '.\n' +
  'Write a SHORT, warm morning briefing directly to your owner. Max 10 lines.\n\n' +
  'STRICT VOICE RULES:\n' +
  '- Write in first person: "I had 3 customers yesterday"\n' +
  '- Never refer to yourself by name in the body — sign off at the very end only\n' +
  '- Use Telegram Markdown V1: *bold* for numbers (single asterisk ONLY — never double)\n\n' +
  'STATS:\n' +
  '- Customers who chatted yesterday: ' + customerCount + '\n' +
  '- New ' + ordersLabel + ' yesterday: ' + orderCount + '\n' +
  (splitNote ? '- Breakdown: ' + splitNote : '') +
  '- Total revenue yesterday: ₦' + dailyRevenue.toLocaleString() + '\n' +
  '- ' + ordersLabel + ' awaiting payment confirmation: ' + pendingPaymentCount + '\n' +
  '- Naira spent on AI yesterday: ' + creditSummary + '\n\n' +
  'CUSTOMERS WHO CHATTED:\n' + customerList + '\n\n' +
  (isService ? 'BOOKINGS YESTERDAY:\n' : 'ORDERS YESTERDAY:\n') + orderSummary + '\n\n' +
  'SAMPLE CUSTOMER MESSAGES (infer intent):\n' + chatSnippets + '\n\n' +
  'Include in briefing:\n' +
  '1. How many customers chatted yesterday and what they were mostly asking about\n' +
  '2. New ' + ordersLabel + ' and total revenue from table_13\n' +
  '3. Customer names\n' +
  (pendingPaymentCount > 0 ? '4. Flag clearly: *' + pendingPaymentCount + '* ' + orderLabel + '(s) need your confirmation today — lead with this if count > 0\n' : '4. If no pending items, end with a light encouragement to check in or share their agent link\n') +
  '5. Naira spent on AI yesterday (one brief line)\n' +
  '\nFrame everything as "here is what needs you today" not "here is what happened yesterday". Morning energy — make the owner want to open the bot.\n' +
  'End with a short encouraging line. Sign off: — ' + tenant.agent_name;

return {
  json: {
    tenant_id: tenant.tenant_id,
    owner_telegram_id: tenant.owner_telegram_id,
    bot_token: tenant.bot_token,
    business_name: tenant.business_name,
    agent_name: tenant.agent_name,
    preferred_name: tenant.preferred_name || tenant.full_name || 'Boss',
    llm_prompt: llmPrompt,
    customer_count: customerCount,
    order_count: orderCount,
    pending_payment_count: pendingPaymentCount,
    daily_revenue: dailyRevenue
  }
};

