const prev = $('Build Summary Prompt').first().json;
const groqResponse = $json;

let summary = '';
try {
  summary = groqResponse.choices[0].message.content || 'No summary generated.';
} catch(e) {
  summary = '*' + prev.customer_count + '* customers chatted yesterday.\n' +
    '*' + prev.order_count + '* new orders received.\n' +
    (prev.pending_payment_count > 0 ? '\n⚠️ *' + prev.pending_payment_count + '* order(s) need your confirmation today.\n' : '') +
    '\nHave a productive day!\n\n— ' + prev.agent_name;
}

const greeting = 'Morning ' + prev.preferred_name + '! ☀️\n\n';

return {
  json: {
    text: greeting + summary,
    chat_id: String(prev.owner_telegram_id),
    bot_token: prev.bot_token
  }
};

const tenant = $('Loop Over Tenants1').first().json;
const stats = $('Load Weekly Stats').first().json;

const topProducts = stats.top_products || [];
const productList = topProducts.length > 0
  ? topProducts.map(p => p.product_name + ' (' + p.qty_sold + ' sold)').join(', ')
  : 'None recorded';

const creditUsage = stats.credit_usage || [];
let creditSummary = 'No AI usage this week';
if (creditUsage.length > 0) {
  const totalSpent = creditUsage.reduce((sum, c) => sum + Number(c.naira_spent || 0), 0);
  const topItem = creditUsage[0];
  const labelMap = {
    input_text: 'text messages', input_audio: 'voice notes',
    input_image: 'images received', output_voice: 'voice replies',
    output_image: 'images generated', output_video: 'videos generated'
  };
  const topLabel = labelMap[topItem.action_type] || topItem.action_type;
  creditSummary = '₦' + totalSpent.toLocaleString() + ' total — most on ' + topLabel + ' (₦' + Number(topItem.naira_spent).toLocaleString() + ')';
}

const businessMode = tenant.business_mode || 'product_only';
const isService = businessMode === 'service_only';
const isHybrid = businessMode === 'hybrid_product_led' || businessMode === 'hybrid_service_led';
const ordersLabel = isService ? 'bookings' : 'orders';
const offeringsLabel = isService ? 'services' : 'products';
const orderLabel = isService ? 'booking' : 'order';
const appointmentCount = parseInt(stats.appointment_count) || 0;

const retentionRate = stats.active_previous_weeks > 0
  ? ((stats.active_this_week / stats.active_previous_weeks) * 100).toFixed(0)
  : 0;

const revenueFormatted = Number(stats.total_revenue || 0).toLocaleString();
const avgOrderFormatted = Number(stats.avg_order_value || 0).toLocaleString();

const peakHourFormatted = stats.peak_hour !== null && stats.peak_hour !== undefined
  ? String(parseInt(stats.peak_hour)).padStart(2, '0') + ':00'
  : null;

const llmPrompt =
  'You are ' + tenant.agent_name + ', the AI business agent for ' + tenant.business_name + '.\n' +
  'Write a warm Sunday evening weekly business insights report directly to your owner. Max 12 lines.\n\n' +
  'STRICT VOICE RULES:\n' +
  '- Write in first person: "I saw ' + (stats.total_orders || 0) + ' ' + ordersLabel + ' this week"\n' +
  '- Never refer to yourself by name in the body — sign off at the very end only\n' +
  '- Use Telegram Markdown V1: *bold* for numbers (single asterisk ONLY — never double)\n\n' +
  'WEEKLY STATS (last 7 days):\n' +
  '- Unique customers: ' + (stats.unique_customers || 0) + '\n' +
  '- Total ' + ordersLabel + ': ' + (stats.total_orders || 0) + '\n' +
  (isHybrid && appointmentCount > 0 ? '- Appointments specifically: ' + appointmentCount + '\n' : '') +
  '- Total revenue: ₦' + revenueFormatted + '\n' +
  '- Average ' + orderLabel + ' value: ₦' + avgOrderFormatted + '\n' +
  '- Customers who ' + (isService ? 'booked' : 'ordered') + ': ' + (stats.ordering_customers || 0) + '\n' +
  '- Active days: ' + (stats.active_days || 0) + ' of 7\n' +
  '- Avg messages per customer: ' + (stats.avg_messages ? Number(stats.avg_messages).toFixed(1) : 0) + '\n\n' +
  'TOP ' + offeringsLabel.toUpperCase() + ':\n' + productList + '\n\n' +
  'PEAK ACTIVITY TIME:\n' +
  (peakHourFormatted ? peakHourFormatted + ' Lagos time (' + stats.peak_interactions + ' interactions)' : 'Not enough data') + '\n\n' +
  'CUSTOMER RETENTION:\n' +
  '- Active this week: ' + (stats.active_this_week || 0) + '\n' +
  '- Active in prior weeks: ' + (stats.active_previous_weeks || 0) + '\n' +
  '- Retention rate: ' + retentionRate + '%\n\n' +
  'NAIRA SPENT ON AI THIS WEEK:\n' + creditSummary + '\n\n' +
  'Include in report:\n' +
  '1. Total ' + ordersLabel + ' and revenue\n' +
  '2. Top ' + offeringsLabel + ' performing this week\n' +
  '3. Peak hour — suggest best time to post offers or respond\n' +
  '4. Retention — kudos if over 50%, gentle nudge if under\n' +
  '5. One specific actionable tip based on the data\n' +
  '6. Naira spent on AI (one brief line)\n' +
  '\nThis lands on Sunday evening — the owner is wrapping up the week and thinking about the week ahead. End with one forward-looking line about the coming week. Sign off: — ' + tenant.agent_name;

return {
  json: {
    tenant_id: tenant.tenant_id,
    owner_telegram_id: tenant.owner_telegram_id,
    bot_token: tenant.bot_token,
    business_name: tenant.business_name,
    agent_name: tenant.agent_name,
    preferred_name: tenant.preferred_name || tenant.full_name || 'Boss',
    llm_prompt: llmPrompt,
    total_orders: stats.total_orders || 0,
    total_revenue: revenueFormatted,
    retention_rate: retentionRate
  }
};

